INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '35f47338-de39-4380-9dac-28c1575b0d2a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Flask Routing — Parameters, Converters, and Blueprint Prefixes$escape$,
  $escape$Flask routes are registered via `@app.route()` or `app.add_url_rule()`. Route parameters are captured with `<variable>` syntax; converters like `<int:id>` or `<path:slug>` handle type coercion and 404-on-mismatch automatically — no manual casting needed.

For grouping and prefixing, Flask's `Blueprint` is the idiomatic tool. A Blueprint declared with `url_prefix='/api/v1/users'` applies that prefix to every route registered on it, and you register it on the app with `app.register_blueprint()`. This keeps route definitions co-located with their handlers instead of scattered across `app.py`.

Converters available out of the box: `string` (default), `int`, `float`, `path` (accepts slashes), `uuid`. You can register custom converters via `app.url_map.converters`. Use `url_for('blueprint_name.view_func')` to generate URLs — never hardcode paths. When a route accepts multiple HTTP methods, pass them explicitly with `methods=['GET', 'POST']`; Flask returns 405 automatically for unlisted verbs.$escape$,
  $escape$from flask import Flask, Blueprint, url_for

users_bp = Blueprint('users', __name__, url_prefix='/api/v1/users')

@users_bp.route('/', methods=['GET'])
def list_users():
    return {'users': []}

@users_bp.route('/<int:user_id>', methods=['GET', 'PUT'])
def user_detail(user_id: int):
    # user_id is already an int; Flask 404s if it's not
    return {'id': user_id}

@users_bp.route('/<int:user_id>/posts/<path:slug>')
def user_post(user_id: int, slug: str):
    return url_for('users.user_post', user_id=user_id, slug=slug)

app = Flask(__name__)
app.register_blueprint(users_bp)$escape$,
