INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8290e4ec-3b84-490d-8109-e66a428cb22e',
  '00000000-0000-0000-0000-000000000001',
  $escape$Flask Auth Middleware — JWT Validation Without the Bloat$escape$,
  $escape$Flask has no built-in auth layer, so the cleanest pattern is a decorator-based middleware using `functools.wraps`. For JWT validation, decode the token in a reusable `@require_auth` decorator using `PyJWT`, attach the payload to `flask.g`, and let route handlers read from `g.user`. Flask's `g` is request-scoped and torn down automatically — no thread-safety concerns.

Avoid `flask-login` for stateless APIs; it's session-cookie-oriented and adds unnecessary overhead. If you need session-based auth for server-rendered flows, use Flask's signed cookie session (`app.secret_key` + `flask.session`) — it's HMAC-signed but not encrypted, so never store sensitive data there.

For role-based access, parameterize the decorator: `@require_auth(role='admin')`. This keeps authorization logic out of route handlers and centralizes token verification. Register an `@app.errorhandler(401)` and `@app.errorhandler(403)` to return consistent JSON error shapes rather than HTML. Blueprint-level `before_request` hooks work well for applying auth to entire feature groups without decorating every route.$escape$,
  $escape$import jwt
from functools import wraps
from flask import request, g, jsonify, current_app

def require_auth(role=None):
    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            token = request.headers.get('Authorization', '').removeprefix('Bearer ')
            if not token:
                return jsonify(error='Missing token'), 401
            try:
                payload = jwt.decode(token, current_app.config['JWT_SECRET'], algorithms=['HS256'])
            except jwt.ExpiredSignatureError:
                return jsonify(error='Token expired'), 401
            except jwt.InvalidTokenError:
                return jsonify(error='Invalid token'), 401
            if role and payload.get('role') != role:
                return jsonify(error='Forbidden'), 403
            g.user = payload
            return f(*args, **kwargs)
        return wrapper
    return decorator$escape$,
  $escape$python$escape$,
