INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'edffc21d-a2dc-465b-bbf2-3c37c79c62a0',
  '00000000-0000-0000-0000-000000000001',
  $escape$Flask Dependency Injection — App Factory Wiring vs Flask-Injector$escape$,
  $escape$Flask has no built-in DI container — dependencies are wired manually via the app factory pattern. In `create_app()`, you instantiate services (SQLAlchemy instances, Redis clients, custom mailers) and attach them to `app.extensions` or pass them directly into blueprints. This is idiomatic Flask.

The testability payoff is immediate: override any dependency by mutating `app.extensions` after calling `create_app()` with a test config. No container introspection, no patching import paths — just plain Python object replacement before `app.test_client()` runs.

Flask-Injector brings container-style DI using the `injector` library, decorating view functions with `@inject` and binding interfaces to implementations in `Module` subclasses. It handles request-scoped and singleton lifecycles cleanly, but adds indirection that obscures the dependency graph during debugging.

Practical rule: use manual factory wiring until you have 5+ shared services with distinct lifecycle scopes. At that threshold, Flask-Injector's `RequestScope` binding justifies the overhead. For request-scoped transient state — active DB sessions, current user context — use `flask.g`, not `app.extensions`. Mixing the two causes subtle lifetime bugs in threaded workers.$escape$,
  $escape$# app.py — manual DI via app factory
def create_app(overrides=None):
    app = Flask(__name__)
    app.config.from_object("config.Default")
    if overrides:
        app.config.update(overrides)
    app.extensions["mailer"] = EmailService(app.config["SMTP_HOST"])
    app.register_blueprint(routes_bp)
    return app

# test_routes.py — swap dependency without a container
def test_signup_sends_email():
    app = create_app({"SMTP_HOST": "localhost", "TESTING": True})
    app.extensions["mailer"] = FakeMailer()
    with app.test_client() as client:
        client.post("/signup", json={"email": "dev@test.com"})
    assert app.extensions["mailer"].call_count == 1$escape$,
  $escape$python$escape$,
