INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7a616b36-6b83-45d1-8892-4033b142675d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Flask Background Jobs — Celery + Redis Without the Boilerplate$escape$,
  $escape$Flask has no built-in task queue, so background jobs require an external worker. Celery is the standard choice — pair it with Redis as the broker and you get task queues, retries, and scheduled jobs with minimal setup.

Define a Celery instance by passing the Flask app's import name, then configure the broker URL. Use `@celery.task` to decorate any function you want to run asynchronously. Call `.delay()` or `.apply_async()` from your route — the request returns immediately while the worker processes the job out-of-band.

For scheduled jobs, use `celery.conf.beat_schedule` to define periodic tasks with cron-style or interval syntax. Run `celery -A app.celery beat` alongside your worker process.

Key production patterns: set `task_acks_late=True` so tasks aren't acknowledged until completion (prevents loss on worker crash), use `bind=True` with `self.retry()` for exponential backoff, and always set `task_soft_time_limit` to kill runaway tasks before they block the queue. Never call `.get()` on a task inside another task — that deadlocks the worker pool.$escape$,
  $escape$from celery import Celery
from flask import Flask

app = Flask(__name__)
app.config['CELERY_BROKER_URL'] = 'redis://localhost:6379/0'

celery = Celery(app.name, broker=app.config['CELERY_BROKER_URL'])
celery.conf.update(task_acks_late=True, task_soft_time_limit=30)

@celery.task(bind=True, max_retries=3)
def send_email(self, user_id):
    try:
        _dispatch_email(user_id)
    except Exception as exc:
        raise self.retry(exc=exc, countdown=2 ** self.request.retries)

@app.route('/notify/<int:user_id>', methods=['POST'])
def notify(user_id):
    send_email.delay(user_id)
    return {'status': 'queued'}, 202$escape$,
  $escape$python$escape$,
