INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ececf9dc-64e8-4f68-95a9-91378f27d125',
  '00000000-0000-0000-0000-000000000001',
  $escape$Flask Monitoring — Health Checks, Prometheus Metrics, and Distributed Tracing$escape$,
  $escape$Flask has no built-in health check route — you add one manually, but do it right. Return database and cache reachability, not just HTTP 200. For metrics, `prometheus-flask-exporter` auto-instruments every route with request counts, latency histograms, and in-flight gauges by simply calling `PrometheusMetrics(app)`. It mounts `/metrics` automatically, which Prometheus scrapes directly. For distributed tracing, `opentelemetry-instrumentation-flask` patches Flask's request lifecycle — wrap your app with `FlaskInstrumentor().instrument_app(app)` and configure an OTLP exporter to ship spans to Jaeger or Tempo. Pair this with `opentelemetry-instrumentation-sqlalchemy` so DB queries appear as child spans automatically. One gotcha: health check routes pollute your metrics with noise — exclude them via `PrometheusMetrics(app, excluded_paths=['/health'])`. For structured trace context in logs, pull `trace_id` from `trace.get_current_span().get_span_context()` and inject it into your Structlog or standard logging pipeline so every log line is correlated to a trace.$escape$,
  $escape$from flask import Flask, jsonify
from prometheus_flask_exporter import PrometheusMetrics
from opentelemetry.instrumentation.flask import FlaskInstrumentor
from opentelemetry.sdk.trace import TracerProvider
from opentelemetry.exporter.otlp.proto.grpc.trace_exporter import OTLPSpanExporter
from opentelemetry.sdk.trace.export import BatchSpanProcessor
import sqlalchemy

app = Flask(__name__)
metrics = PrometheusMetrics(app, excluded_paths=["/health"])

tracer_provider = TracerProvider()
tracer_provider.add_span_processor(BatchSpanProcessor(OTLPSpanExporter(endpoint="http://otel-collector:4317")))
FlaskInstrumentor().instrument_app(app, tracer_provider=tracer_provider)

@app.route("/health")
def health():
    try:
        db.session.execute(sqlalchemy.text("SELECT 1"))
        return jsonify(status="ok", db="reachable"), 200
    except Exception as e:
        return jsonify(status="degraded", error=str(e)), 503$escape$,
  $escape$python$escape$,
